const msg = $input.first().json.message || {};
const text = (msg.text || msg.caption || '').trim();
const chatId = msg.chat?.id;

if (msg.photo?.length) {
  const largest = msg.photo[msg.photo.length - 1];
  return [{
    json: {
      route: 'photo_edit',
      chatId,
      text: text || 'Отредактируй это изображение качественно и естественно.',
      fileId: largest.file_id,
      message: msg
    }
  }];
}

if (!text) {
  return [{ json: { route: 'no_text', chatId, text: '', message: msg } }];
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.imageCache) staticData.imageCache = {};
const chatKey = String(chatId);
const hasCache = Boolean(staticData.imageCache[chatKey]);

let route = 'chat';
if (text === '/start') route = 'start';
else if (text === '/help') route = 'help';
else if (/^нарисуй\s+/i.test(text)) route = 'image_generate';
else if (hasCache && /(отредактир|редактир|измени|улучши|добавь|убери|сделай).*(фото|изображ|картин)|^(сделай|убери|добавь)\b/i.test(text)) route = 'image_edit_cached';

const imagePrompt = route === 'image_generate' ? text.replace(/^нарисуй\s+/i, '').trim() : '';

if (route === 'image_generate' && !imagePrompt) {
  return [{ json: { route: 'image_generate_empty', chatId, text, message: msg } }];
}

return [{ json: { route, chatId, text, message: msg, imagePrompt, fileId: null } }];

try {
  const prep = $('Подготовка сообщения').first().json;
  const chatId = prep.chatId;
  let instruction = prep.text;
  let imageDataUrl = null;
  const staticData = $getWorkflowStaticData('global');
  staticData.imageCache = staticData.imageCache || {};
  const chatKey = String(chatId);

  async function binaryItemToDataUrl(item, itemIndex) {
    if (!item?.binary) return null;
    const binKey = item.binary.data ? 'data' : Object.keys(item.binary)[0];
    if (!binKey) return null;
    const meta = item.binary[binKey];
    const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, binKey);
    const mime = meta?.mimeType || 'image/jpeg';
    return `data:${mime};base64,${buffer.toString('base64')}`;
  }

  if (prep.route === 'photo_edit') {
    const items = $input.all();
    let loaded = false;
    for (let i = 0; i < items.length; i++) {
      try {
        imageDataUrl = await binaryItemToDataUrl.call(this, items[i], i);
        if (imageDataUrl) {
          loaded = true;
          break;
        }
      } catch (_) {
        /* try next item */
      }
    }
    if (!loaded) {
      const dl = $('Скачать фото').first();
      if (dl?.binary) {
        imageDataUrl = await binaryItemToDataUrl.call(this, dl, 0);
      }
    }
    if (imageDataUrl) {
      staticData.imageCache[chatKey] = imageDataUrl;
    } else {
      return [{
        json: {
          chatId,
          error: true,
          errorText: 'Не удалось прочитать фото из Telegram. В узле «Скачать фото» включите Download и привяжите Telegram API credential.'
        }
      }];
    }
  } else if (prep.route === 'image_edit_cached') {
    imageDataUrl = staticData.imageCache[chatKey] || null;
    if (!imageDataUrl) {
      return [{
        json: {
          chatId,
          error: true,
          errorText: 'Нет сохранённого изображения. Сначала отправьте фото с подписью или «нарисуй …».'
        }
      }];
    }
  } else if (prep.route === 'image_generate') {
    instruction = `Сгенерируй детальное качественное изображение: ${prep.imagePrompt || instruction}`;
  }

  const content = [];
  if (imageDataUrl) {
    content.push({ type: 'image_url', image_url: { url: imageDataUrl } });
  }
  content.push({ type: 'text', text: instruction });

  return [{
    json: {
      chatId,
      caption: instruction.slice(0, 500),
      openRouterBody: {
        model: 'google/gemini-3.1-flash-image-preview',
        modalities: ['image', 'text'],
        messages: [{ role: 'user', content }]
      }
    }
  }];
} catch (err) {
  const prep = $('Подготовка сообщения').first()?.json || {};
  return [{
    json: {
      chatId: prep.chatId,
      error: true,
      errorText: `Ошибка подготовки изображения: ${err.message || String(err)}`
    }
  }];
}

const collect = $('Собрать запрос Nano Banana').first().json;
const chatId = collect.chatId;
const caption = collect.caption || '';

if (collect.error) {
  return [{ json: { chatId, text: collect.errorText, responseType: 'text' } }];
}

const data = $input.first().json;
if (data.error || (data.statusCode && data.statusCode >= 400)) {
  const errMsg = data.error?.message || data.message || JSON.stringify(data.error || data).slice(0, 300);
  return [{ json: { chatId, text: `Ошибка OpenRouter: ${errMsg}`, responseType: 'text' } }];
}

const message = data.choices?.[0]?.message;
const images = message?.images || [];
let imageUrl = images[0]?.image_url?.url;

if (!imageUrl && typeof message?.content === 'string') {
  const m = message.content.match(/data:image\/[^;]+;base64,[A-Za-z0-9+/=]+/);
  if (m) imageUrl = m[0];
}

if (!imageUrl) {
  const fallback = typeof message?.content === 'string' ? message.content : 'Изображение не получено от API.';
  return [{ json: { chatId, text: fallback.slice(0, 3500), responseType: 'text' } }];
}

const base64Match = imageUrl.match(/^data:image\/([^;]+);base64,(.+)$/);
if (!base64Match) {
  return [{ json: { chatId, text: 'Неверный формат изображения в ответе API.', responseType: 'text' } }];
}

const staticData = $getWorkflowStaticData('global');
staticData.imageCache = staticData.imageCache || {};
staticData.imageCache[String(chatId)] = imageUrl;

return [{
  json: { chatId, caption, responseType: 'photo' },
  binary: {
    image: {
      data: base64Match[2],
      mimeType: `image/${base64Match[1]}`,
      fileName: 'nano_banana.png'
    }
  }
}];

const instruction = (typeof query === 'string' ? query : (query?.input || query?.instruction || '')).trim();
if (!instruction) {
  return 'Укажите описание изображения или правки.';
}

const chatId = String($('Подготовка сообщения').first().json.chatId);
const staticData = $getWorkflowStaticData('global');
staticData.imageCache = staticData.imageCache || {};
staticData.pendingImage = staticData.pendingImage || {};
const cached = staticData.imageCache[chatId];

const content = [];
if (cached) {
  content.push({ type: 'image_url', image_url: { url: cached } });
}
content.push({ type: 'text', text: instruction });

const body = {
  model: 'google/gemini-3.1-flash-image-preview',
  modalities: ['image', 'text'],
  messages: [{ role: 'user', content }]
};

try {
  const response = await this.helpers.httpRequestWithAuthentication.call(
    this,
    'httpHeaderAuth',
    {
      method: 'POST',
      url: 'https://openrouter.ai/api/v1/chat/completions',
      headers: { 'HTTP-Referer': 'https://n8n.io', 'Content-Type': 'application/json' },
      body,
      json: true,
      timeout: 120000
    }
  );

  const message = response?.choices?.[0]?.message;
  const images = message?.images || [];
  let imageUrl = images[0]?.image_url?.url;
  if (!imageUrl && typeof message?.content === 'string') {
    const m = message.content.match(/data:image\/[^;]+;base64,[A-Za-z0-9+/=]+/);
    if (m) imageUrl = m[0];
  }
  if (!imageUrl) {
    return (typeof message?.content === 'string' ? message.content : 'Не удалось получить изображение от API.').slice(0, 500);
  }

  staticData.imageCache[chatId] = imageUrl;
  const match = imageUrl.match(/^data:image\/([^;]+);base64,(.+)$/);
  if (match) {
    staticData.pendingImage[chatId] = {
      base64: match[2],
      mimeType: `image/${match[1]}`,
      caption: instruction.slice(0, 500)
    };
  }
  return 'Изображение готово и будет отправлено в чат. Кратко опиши пользователю, что сделано.';
} catch (e) {
  return `Ошибка Редактор_изображений: ${e.message || e}. Проверьте credential httpHeaderAuth (OpenRouter Bearer).`;
}

const chatId = String($('Подготовка сообщения').first().json.chatId);
const staticData = $getWorkflowStaticData('global');
staticData.pendingImage = staticData.pendingImage || {};
const pending = staticData.pendingImage[chatId];

if (pending) {
  delete staticData.pendingImage[chatId];
  return [{
    json: { chatId, caption: pending.caption, responseType: 'photo' },
    binary: {
      image: {
        data: pending.base64,
        mimeType: pending.mimeType || 'image/png',
        fileName: 'generated.png'
      }
    }
  }];
}

const output = ($input.first().json.output || $input.first().json.text || 'Извините, не удалось сформировать ответ.').toString();
return [{ json: { chatId, text: output.slice(0, 4096), responseType: 'text' } }];
